import { promises as fs } from "node:fs";
import path from "node:path";

export type Member = {
  id: string;
  name: string;
  username: string;
  password: string;
  color: string;
  canManage: boolean;
};

export type Task = {
  id: string;
  title: string;
  assigneeId: string;
  date: string;
  time?: string;
  repeatLabel: string;
  done: boolean;
  completedAt?: string | null;
};

export type ShoppingItem = {
  id: string;
  title: string;
  assigneeId: string;
  done: boolean;
};

export type AppData = {
  members: Member[];
  tasks: Task[];
  shoppingItems: ShoppingItem[];
};

const dataFilePath = path.join(process.cwd(), "data", "natahu.json");

function getCurrentMonthKey() {
  return new Date().toISOString().slice(0, 7);
}

function normalizeAppData(data: AppData) {
  const currentMonthKey = getCurrentMonthKey();

  return {
    ...data,
    tasks: data.tasks.filter((task) => {
      if (!task.done) {
        return true;
      }

      if (!task.completedAt) {
        return false;
      }

      return task.completedAt.slice(0, 7) === currentMonthKey;
    }),
  };
}

export async function readAppData() {
  const raw = await fs.readFile(dataFilePath, "utf8");
  const parsed = JSON.parse(raw) as AppData;
  const normalized = normalizeAppData(parsed);

  if (JSON.stringify(parsed) !== JSON.stringify(normalized)) {
    await writeAppData(normalized);
  }

  return normalized;
}

export async function writeAppData(data: AppData) {
  const normalized = normalizeAppData(data);
  await fs.writeFile(dataFilePath, JSON.stringify(normalized, null, 2), "utf8");
}
